TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
Context("Numeric")->variables->add(y=>'Real');
parser::Assignment->Allow;
$equation = Formula("y = 3 x + 5");
$gt = GraphTool("{line, solid, (0, 5), (1, 8)}")->with(
  bBox => [-11, 11, 11, -11],
  showInStatic => 0,
);

$image_1 = createLaTeXImage();
$image_1->addToPreamble(latexImagePreamble());
